 64	export default defineCommand({
 65	  meta: {
 66	    name: "story-continue",
 67	    description: "Continue an explicit retained story implementor session.",
 68	  },
 69	  args: {
 70	    "spec-pack-root": {
 71	      type: "string",
 72	      description: "Absolute or relative path to the spec-pack root",
 73	      required: true,
 74	    },
 75	    "story-id": {
 76	      type: "string",
 77	      description: "The story id to continue",
 78	      required: true,
 79	    },
 80	    provider: {
 81	      type: "string",
 82	      description: "Provider name from the continuation handle",
 83	      required: true,
 84	    },
 85	    "session-id": {
 86	      type: "string",
 87	      description: "Explicit session id from the continuation handle",
 88	      required: true,
 89	    },
 90	    config: {
 91	      type: "string",
 92	      description: "Explicit run-config file relative to the spec-pack root",
 93	    },
 94	    "followup-file": {
 95	      type: "string",
 96	      description: "Path to a follow-up prompt file",
 97	    },
 98	    "followup-text": {
 99	      type: "string",
100	      description: "Inline follow-up request text",
101	    },
102	    json: {
103	      type: "boolean",
104	      description: "Emit the structured JSON envelope on stdout",
105	    },
106	  },
107	  async run({ args }) {
108	    const startedAt = new Date().toISOString();
109	    const artifactPath = await nextGroupedArtifactPath(
110	      args["spec-pack-root"],
111	      args["story-id"],
112	      "continue"
113	    );
114	
115	    try {
116	      if (
117	        (!args["followup-file"] && !args["followup-text"]) ||
118	        (args["followup-file"] && args["followup-text"])
119	      ) {
120	        const envelope: OutputEnvelope = createResultEnvelope({
121	          command: "story-continue",
122	          outcome: "error",
123	          errors: [
124	            {
125	              code: "INVALID_INVOCATION",
126	              message:
127	                "Provide exactly one of --followup-file or --followup-text.",
128	            },
129	          ],
130	          artifacts: [
131	            {
132	              kind: "result-envelope",
133	              path: artifactPath,
134	            },
135	          ],
136	          startedAt,
137	          finishedAt: new Date().toISOString(),
138	        });
139	
140	        await writeJsonArtifact(artifactPath, envelope);
141	        emitOutput({
142	          envelope,
143	          json: Boolean(args.json),
144	        });
145	        process.exitCode = exitCodeForStatus(envelope.status);
146	        return;
147	      }
148	
149	      const followupRequest = args["followup-file"]
150	        ? await readTextFile(args["followup-file"])
151	        : (args["followup-text"] as string);
152	      const outcome = await runStoryContinue({
153	        specPackRoot: args["spec-pack-root"],
154	        storyId: args["story-id"],
155	        provider: args.provider,
156	        sessionId: args["session-id"],
157	        followupRequest,
158	        configPath: args.config,
159	        env: process.env,
160	      });
161	      const envelope = cliResultEnvelopeSchema(implementorResultSchema).parse(
162	        createResultEnvelope({
163	          command: "story-continue",
164	          outcome: outcome.outcome,
165	          result: outcome.result,
166	          errors: outcome.errors,
167	          warnings: outcome.warnings,
168	          artifacts: [
169	            {
170	              kind: "result-envelope",
171	              path: artifactPath,
172	            },
173	          ],
174	          startedAt,
175	          finishedAt: new Date().toISOString(),
176	        })
177	      );
178	
179	      await writeJsonArtifact(artifactPath, envelope);
180	      emitOutput({
181	        envelope,
182	        json: Boolean(args.json),
183	      });
184	      process.exitCode = exitCodeForStatus(envelope.status);
185	    } catch (error) {
186	      const envelope: OutputEnvelope = createResultEnvelope({
187	        command: "story-continue",
188	        outcome:
189	          error instanceof ZodError ||
190	          (error instanceof Error &&
191	            error.message.toLowerCase().includes("config"))
192	            ? "blocked"
193	            : "error",
194	        errors: [
195	          {
196	            code:
197	              error instanceof ZodError ||
198	              (error instanceof Error &&
199	                error.message.toLowerCase().includes("config"))
200	                ? "INVALID_RUN_CONFIG"
201	                : "UNEXPECTED_ERROR",
202	            message: error instanceof Error ? error.message : String(error),
203	          },
204	        ],
205	        artifacts: [
206	          {
207	            kind: "result-envelope",
208	            path: artifactPath,
209	          },
210	        ],
211	        startedAt,
212	        finishedAt: new Date().toISOString(),
213	      });
214	
215	      await writeJsonArtifact(artifactPath, envelope);
216	      emitOutput({
217	        envelope,
218	        json: Boolean(args.json),
219	      });
220	      process.exitCode = exitCodeForStatus(envelope.status);
221	    }
222	  },
223	});

